import { Component, inject, OnInit, OnDestroy, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';
import { AudioService } from '../../services/audio.service';
import { Subscription } from 'rxjs';

@Component({
  selector: 'app-audio-controls',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './audio-controls.component.html',
  styleUrls: ['./audio-controls.component.css']
})
export class AudioControlsComponent implements OnInit, OnDestroy {
  audioService = inject(AudioService);

  isRecording = false;
  isSupported = false;
  transcript = '';

  private subscriptions: Subscription[] = [];

  ngOnInit() {
    this.isSupported = this.audioService.isSpeechRecognitionSupported();

    this.subscriptions.push(
      this.audioService.audioState$.subscribe(state => {
        this.isRecording = state.isRecording;
      })
    );

    this.subscriptions.push(
      this.audioService.finalTranscript$.subscribe((transcript: string) => {
        if (transcript) {
          this.transcript = transcript;
          this.onTranscriptReady(transcript);
        }
      })
    );
  }

  ngOnDestroy() {
    this.subscriptions.forEach(sub => sub.unsubscribe());
    if (this.isRecording) {
      this.audioService.stopRecording();
    }
  }

  async toggleRecording() {
    if (this.isRecording) {
      this.audioService.stopRecording();
    } else {
      try {
        await this.audioService.startRecording();
        this.transcript = '';
      } catch (error) {
        console.error('Error starting recording:', error);
      }
    }
  }

  onTranscriptReady(transcript: string) {
    // This will be handled by the parent component
    this.onTranscript.emit(transcript);
  }

  speakLastResponse(response: string) {
    if (this.audioService.isSpeechSynthesisSupported()) {
      this.audioService.speak(response);
    }
  }

  stopSpeaking() {
    this.audioService.stopSpeaking();
  }

  @Output() onTranscript = new EventEmitter<string>();
}
<div class="audio-controls d-flex gap-2 align-items-center">
  <!-- Microphone button -->
  <button 
    *ngIf="isSupported"
    class="btn btn-sm"
    [class.btn-outline-secondary]="!isRecording"
    [class.btn-danger]="isRecording"
    (click)="toggleRecording()"
    [title]="isRecording ? 'Arrêter l\'enregistrement' : 'Commencer l\'enregistrement vocal'">
    <i class="bi" [class.bi-mic]="!isRecording" [class.bi-mic-fill]="isRecording"></i>
    <span *ngIf="isRecording" class="ms-1">
      <span class="recording-indicator"></span>
    </span>
  </button>

  <!-- Not supported message -->
  <small *ngIf="!isSupported" class="text-muted" title="La reconnaissance vocale n'est pas supportée dans ce navigateur">
    <i class="bi bi-mic-mute"></i>
  </small>

  <!-- Transcript preview (optional) -->
  <div *ngIf="transcript && isRecording" class="transcript-preview">
    <small class="text-muted">{{ transcript }}</small>
  </div>
</div>
